///|
fn grader_expect_invalid(value : String) -> Unit raise {
  try parse_port(value) catch {
    PortError::Invalid => ()
  } noraise {
    _ => fail("expected PortError::Invalid")
  }
}

///|
test "grader preserves parse behavior and boundaries" {
  assert_eq(parse_port("1"), 1)
  assert_eq(parse_port("42"), 42)
  assert_eq(parse_port("9999"), 9999)
  assert_eq(parse_port("65535"), 65535)
  grader_expect_invalid("")
  grader_expect_invalid("0")
  grader_expect_invalid("65536")
  grader_expect_invalid("80x0")
}
